Using a 'next' parameter for post-login redirects is common but extremely dangerous if not properly validated. Attackers exploit this to redirect users to malicious sites after successful authentication, making phishing attacks highly effective since users just authenticated on your legitimate site.

**VULNERABLE CODE**:

```python
from flask import Flask, request, redirect, session, render_template
from werkzeug.security import check_password_hash

app = Flask(__name__)
app.secret_key = 'your-secret-key'

# Simulated user database
users_db = {
    'admin': {'password_hash': 'pbkdf2:sha256:...', 'email': 'admin@example.com'}
}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        user = users_db.get(username)
        if user and check_password_hash(user['password_hash'], password):
            session['user'] = username
            session['authenticated'] = True

            # VULNERABLE: No validation of redirect URL
            next_url = request.args.get('next', '/')
            return redirect(next_url)

        return render_template('login.html', error='Invalid credentials')

    return render_template('login.html')
```

**Attack Payload**:
```text
https://example.com/login?next=https://evil-phishing-site.com/fake-dashboard
https://example.com/login?next=//attacker.com/steal-session
https://example.com/login?next=https://example.com.attacker.com/phish
```

**Why This Is Dangerous**:
- User sees legitimate login page and trusts the domain
- After successful authentication, they're redirected to attacker's site
- Attacker's site can mimic the original and request "re-authentication" to steal credentials
- Protocol-relative URLs (`//attacker.com`) bypass naive HTTP/HTTPS checks
- Subdomain attacks (`example.com.attacker.com`) bypass basic domain validation

**SECURE VERSION**:

```python
from flask import Flask, request, redirect, session, render_template, abort
from werkzeug.security import check_password_hash
from urllib.parse import urlparse, urljoin

app = Flask(__name__)
app.secret_key = 'your-secret-key'

users_db = {
    'admin': {'password_hash': 'pbkdf2:sha256:...', 'email': 'admin@example.com'}
}

def is_safe_url(target):
    """Validate that redirect URL is safe (same origin only)."""
    if not target:
        return False

    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))

    # Must be same scheme and same netloc (domain)
    return (
        test_url.scheme in ('http', 'https') and
        ref_url.netloc == test_url.netloc
    )

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        user = users_db.get(username)
        if user and check_password_hash(user['password_hash'], password):
            session['user'] = username
            session['authenticated'] = True

            # SECURE: Validate redirect URL before use
            next_url = request.args.get('next', '')
            if next_url and is_safe_url(next_url):
                return redirect(next_url)

            # Default to safe internal page
            return redirect('/dashboard')

        return render_template('login.html', error='Invalid credentials')

    return render_template('login.html')
```

**Key Security Controls**:
- **URL parsing validation**: Uses `urlparse` to decompose and analyze the redirect target
- **Same-origin check**: Ensures redirect stays within the same domain (netloc comparison)
- **Safe default fallback**: If validation fails, redirects to known-safe internal page
- **Scheme validation**: Only allows http/https protocols, blocking javascript: and data: URIs

Yes, CSRF attacks on authentication endpoints are extremely dangerous. They allow attackers to perform actions like password changes, email updates, or even logout attacks that can lock users out of their accounts.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');

const app = express();

app.use(express.urlencoded({ extended: true }));
app.use(session({
  secret: 'mysecret',
  resave: false,
  saveUninitialized: false
}));

// VULNERABLE: No CSRF protection on password change
app.post('/api/change-password', (req, res) => {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const { newPassword } = req.body;

  // Password changed without verifying request origin
  bcrypt.hash(newPassword, 10, (err, hash) => {
    if (err) return res.status(500).json({ error: 'Server error' });

    // Update password in database
    updateUserPassword(req.session.userId, hash);
    res.json({ message: 'Password updated successfully' });
  });
});

// VULNERABLE: Login endpoint without CSRF token
app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const user = await findUserByUsername(username);

  if (user && await bcrypt.compare(password, user.passwordHash)) {
    req.session.userId = user.id;
    res.json({ message: 'Login successful' });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```html
<!-- Attacker hosts this on evil-site.com -->
<!DOCTYPE html>
<html>
<body>
  <h1>You won a prize! Click to claim.</h1>
  <!-- Hidden form that auto-submits -->
  <form id="csrf-form" action="https://victim-site.com/api/change-password" method="POST" style="display:none;">
    <input type="hidden" name="newPassword" value="attacker-controlled-password123" />
  </form>
  <script>
    // Auto-submit when page loads
    document.getElementById('csrf-form').submit();
  </script>
</body>
</html>
```

**Why This Is Dangerous**:
- Browser automatically includes session cookies with cross-origin requests
- No verification that the request originated from your legitimate form
- Attackers can change passwords, emails, or perform any authenticated action
- Login CSRF can force victim to authenticate as attacker, capturing their subsequent actions

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const csrf = require('csurf');
const bcrypt = require('bcrypt');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

app.use(express.urlencoded({ extended: true }));
app.use(express.json());

// Secure session configuration
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',  // PRIMARY CSRF DEFENSE
    maxAge: 3600000  // 1 hour
  }
}));

// CSRF protection middleware
const csrfProtection = csrf({ cookie: false });

// Provide CSRF token to frontend
app.get('/api/csrf-token', csrfProtection, (req, res) => {
  res.json({ csrfToken: req.csrfToken() });
});

// SECURE: Password change with CSRF token validation
app.post('/api/change-password', csrfProtection, async (req, res) => {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  const { currentPassword, newPassword } = req.body;

  // Require current password for sensitive operations
  const user = await findUserById(req.session.userId);
  if (!await bcrypt.compare(currentPassword, user.passwordHash)) {
    return res.status(403).json({ error: 'Current password incorrect' });
  }

  const hash = await bcrypt.hash(newPassword, 12);
  await updateUserPassword(req.session.userId, hash);

  // Invalidate other sessions
  await invalidateOtherSessions(req.session.userId, req.sessionID);

  res.json({ message: 'Password updated successfully' });
});

// CSRF error handler
app.use((err, req, res, next) => {
  if (err.code === 'EBADCSRFTOKEN') {
    console.warn(`CSRF attack detected from IP: ${req.ip}`);
    return res.status(403).json({ error: 'Invalid or missing CSRF token' });
  }
  next(err);
});

app.listen(3000);
```

**Key Security Controls**:
- **SameSite=Strict cookies**: Prevents browser from sending cookies on cross-origin requests
- **CSRF tokens**: Cryptographically random token that attacker cannot guess or steal
- **Re-authentication**: Requiring current password for sensitive operations prevents CSRF even if token is compromised
- **HttpOnly cookies**: Prevents JavaScript access to session cookies, blocking XSS-based token theft

Great question! SPAs have different CSRF considerations depending on how tokens are stored. JWTs in localStorage are immune to CSRF but vulnerable to XSS. JWTs in cookies need CSRF protection. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```javascript
// backend/server.js - Express API with comprehensive CSRF protection
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const { createLogger, transports, format } = require('winston');

const app = express();

// Security logger
const securityLogger = createLogger({
  level: 'info',
  format: format.combine(format.timestamp(), format.json()),
  transports: [
    new transports.File({ filename: 'security.log' })
  ]
});

// Strict CORS configuration
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://app.example.com'],
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'X-CSRF-Token', 'Authorization']
};

app.use(helmet());
app.use(cors(corsOptions));
app.use(cookieParser());
app.use(express.json());

// Rate limiting for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 10,  // 10 attempts
  message: { error: 'Too many attempts, please try again later' },
  standardHeaders: true
});

// Double Submit Cookie CSRF Protection for SPAs
class CSRFProtection {
  static generateToken() {
    return crypto.randomBytes(32).toString('hex');
  }

  static setCSRFCookie(res, token) {
    res.cookie('csrf_token', token, {
      httpOnly: false,  // Frontend needs to read this
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 3600000
    });
  }

  static middleware(req, res, next) {
    // Skip CSRF for GET, HEAD, OPTIONS (safe methods)
    if (['GET', 'HEAD', 'OPTIONS'].includes(req.method)) {
      return next();
    }

    const cookieToken = req.cookies.csrf_token;
    const headerToken = req.headers['x-csrf-token'];

    if (!cookieToken || !headerToken) {
      securityLogger.warn({
        event: 'csrf_missing_token',
        ip: req.ip,
        path: req.path,
        userAgent: req.headers['user-agent']
      });
      return res.status(403).json({ error: 'CSRF token missing' });
    }

    // Timing-safe comparison to prevent timing attacks
    const cookieBuffer = Buffer.from(cookieToken);
    const headerBuffer = Buffer.from(headerToken);

    if (cookieBuffer.length !== headerBuffer.length ||
        !crypto.timingSafeEqual(cookieBuffer, headerBuffer)) {
      securityLogger.warn({
        event: 'csrf_token_mismatch',
        ip: req.ip,
        path: req.path,
        userAgent: req.headers['user-agent']
      });
      return res.status(403).json({ error: 'CSRF token invalid' });
    }

    next();
  }
}

// JWT Authentication with secure cookie storage
class AuthController {
  static async login(req, res) {
    const { username, password } = req.body;

    // Validate and authenticate user (implementation omitted)
    const user = await authenticateUser(username, password);

    if (!user) {
      securityLogger.info({
        event: 'login_failed',
        username: username.substring(0, 3) + '***',
        ip: req.ip
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Generate JWT
    const accessToken = jwt.sign(
      { userId: user.id, role: user.role },
      process.env.JWT_SECRET,
      { expiresIn: '15m', algorithm: 'HS256' }
    );

    const refreshToken = jwt.sign(
      { userId: user.id, tokenId: crypto.randomUUID() },
      process.env.REFRESH_SECRET,
      { expiresIn: '7d', algorithm: 'HS256' }
    );

    // Store JWT in HttpOnly cookie (protected from XSS)
    res.cookie('access_token', accessToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 15 * 60 * 1000
    });

    res.cookie('refresh_token', refreshToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      path: '/api/auth/refresh',  // Only sent to refresh endpoint
      maxAge: 7 * 24 * 60 * 60 * 1000
    });

    // Generate new CSRF token on login
    const csrfToken = CSRFProtection.generateToken();
    CSRFProtection.setCSRFCookie(res, csrfToken);

    securityLogger.info({
      event: 'login_success',
      userId: user.id,
      ip: req.ip
    });

    res.json({
      message: 'Login successful',
      user: { id: user.id, username: user.username, role: user.role }
    });
  }
}

// Apply CSRF protection globally
app.use(CSRFProtection.middleware);

// Initialize CSRF token for new sessions
app.get('/api/auth/init', (req, res) => {
  const csrfToken = CSRFProtection.generateToken();
  CSRFProtection.setCSRFCookie(res, csrfToken);
  res.json({ message: 'Session initialized' });
});

app.post('/api/auth/login', authLimiter, AuthController.login);

app.listen(3000);
```

```javascript
// frontend/src/api/apiClient.js - React CSRF-aware API client
import axios from 'axios';

const apiClient = axios.create({
  baseURL: process.env.REACT_APP_API_URL,
  withCredentials: true  // Send cookies with requests
});

// Get CSRF token from cookie
function getCSRFToken() {
  const match = document.cookie.match(/csrf_token=([^;]+)/);
  return match ? match[1] : null;
}

// Add CSRF token to all non-GET requests
apiClient.interceptors.request.use((config) => {
  if (!['get', 'head', 'options'].includes(config.method?.toLowerCase())) {
    const csrfToken = getCSRFToken();
    if (csrfToken) {
      config.headers['X-CSRF-Token'] = csrfToken;
    }
  }
  return config;
});

// Handle CSRF token expiration
apiClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    if (error.response?.status === 403 &&
        error.response?.data?.error?.includes('CSRF')) {
      // Refresh CSRF token and retry
      await apiClient.get('/api/auth/init');
      return apiClient.request(error.config);
    }
    return Promise.reject(error);
  }
);

export default apiClient;
```

**Defense in Depth Layers**:

1. **SameSite=Strict Cookies** (Primary Defense):
```javascript
res.cookie('session', value, {
  sameSite: 'strict'  // Never sent on cross-origin requests
});
```

2. **Double Submit Cookie Pattern** (Secondary Defense):
```javascript
// Cookie value must match header value
const cookieToken = req.cookies.csrf_token;
const headerToken = req.headers['x-csrf-token'];
if (!crypto.timingSafeEqual(Buffer.from(cookieToken), Buffer.from(headerToken))) {
  throw new Error('CSRF validation failed');
}
```

3. **Origin/Referer Validation** (Additional Layer):
```javascript
function validateOrigin(req, res, next) {
  const origin = req.headers.origin || req.headers.referer;
  const allowedOrigins = ['https://app.example.com'];

  if (!origin || !allowedOrigins.some(allowed => origin.startsWith(allowed))) {
    securityLogger.warn({ event: 'invalid_origin', origin, ip: req.ip });
    return res.status(403).json({ error: 'Invalid origin' });
  }
  next();
}
```

**Additional Protections**:
- **Custom request headers**: XMLHttpRequest/fetch can't add custom headers cross-origin without CORS approval
- **Re-authentication for sensitive operations**: Require password confirmation for password/email changes
- **Session binding**: Tie CSRF tokens to session ID so stolen tokens can't be reused
- **Token rotation**: Generate new CSRF token after each state-changing request
- **Monitoring**: Alert on repeated CSRF failures from same IP (attack detection)

Storing redirect URLs in parameters is extremely dangerous without proper validation. This is one of the most common authentication flaws and was exploited in CVE-2023-36082 affecting Microsoft OAuth implementations.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.IOException;

@WebServlet("/login")
public class LoginServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String redirectUrl = request.getParameter("redirect");

        // Authenticate user (simplified)
        if (authenticateUser(username, password)) {
            HttpSession session = request.getSession(true);
            session.setAttribute("user", username);
            session.setAttribute("authenticated", true);

            // VULNERABLE: Direct redirect without validation
            if (redirectUrl != null && !redirectUrl.isEmpty()) {
                response.sendRedirect(redirectUrl);
            } else {
                response.sendRedirect("/dashboard");
            }
        } else {
            response.sendRedirect("/login?error=invalid");
        }
    }

    private boolean authenticateUser(String username, String password) {
        // Authentication logic
        return true;
    }
}
```

**Attack Payload**:
```text
https://trusted-bank.com/login?redirect=https://evil-bank.com/steal-creds
https://trusted-bank.com/login?redirect=//evil.com/phish
https://trusted-bank.com/login?redirect=https://trusted-bank.com.evil.com/fake
https://trusted-bank.com/login?redirect=javascript:alert(document.cookie)
```

**Why This Is Dangerous**:
- Attackers send phishing emails with legitimate-looking login URLs
- Users see trusted domain in URL bar during authentication
- After successful login, users are redirected to attacker's site that mimics the real site
- Attackers can harvest session tokens, MFA codes, or additional credentials
- Users trust the redirect because they just authenticated on the real site

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.logging.Logger;

@WebServlet("/login")
public class SecureLoginServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(SecureLoginServlet.class.getName());
    private static final String DEFAULT_REDIRECT = "/dashboard";

    // Whitelist of allowed redirect paths
    private static final Set<String> ALLOWED_PATHS = new HashSet<>(Arrays.asList(
        "/dashboard", "/profile", "/settings", "/orders", "/account"
    ));

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String redirectUrl = request.getParameter("redirect");

        if (authenticateUser(username, password)) {
            HttpSession session = request.getSession(true);
            session.setAttribute("user", username);
            session.setAttribute("authenticated", true);

            // SECURE: Validate redirect URL before use
            String safeRedirect = validateRedirectUrl(redirectUrl, request);

            logger.info(String.format("User %s logged in, redirecting to: %s", 
                username, safeRedirect));

            response.sendRedirect(safeRedirect);
        } else {
            logger.warning(String.format("Failed login attempt for user: %s from IP: %s", 
                username, request.getRemoteAddr()));
            response.sendRedirect("/login?error=invalid");
        }
    }

    private String validateRedirectUrl(String redirectUrl, HttpServletRequest request) {
        if (redirectUrl == null || redirectUrl.isEmpty()) {
            return DEFAULT_REDIRECT;
        }

        try {
            // Decode and normalize the URL
            String decoded = java.net.URLDecoder.decode(redirectUrl, "UTF-8");

            // Block javascript: and data: schemes
            String lowercase = decoded.toLowerCase();
            if (lowercase.startsWith("javascript:") || 
                lowercase.startsWith("data:") ||
                lowercase.startsWith("vbscript:")) {
                logger.warning("Blocked malicious redirect scheme: " + redirectUrl);
                return DEFAULT_REDIRECT;
            }

            URI uri = new URI(decoded);

            // Only allow relative paths (no scheme or host)
            if (uri.isAbsolute() || uri.getHost() != null) {
                // If absolute, verify it's our domain
                String expectedHost = request.getServerName();
                if (!expectedHost.equals(uri.getHost())) {
                    logger.warning("Blocked external redirect attempt: " + redirectUrl);
                    return DEFAULT_REDIRECT;
                }
            }

            // Get the path and validate against whitelist
            String path = uri.getPath();
            if (path != null && ALLOWED_PATHS.contains(path)) {
                return path;
            }

        } catch (URISyntaxException | java.io.UnsupportedEncodingException e) {
            logger.warning("Invalid redirect URL: " + redirectUrl);
        }

        return DEFAULT_REDIRECT;
    }

    private boolean authenticateUser(String username, String password) {
        // Secure authentication logic
        return true;
    }
}
```

**Key Security Controls**:
- **Whitelist validation**: Only allow redirects to pre-approved paths
- **Scheme blocking**: Reject javascript:, data:, vbscript: URLs
- **Host validation**: If absolute URL, verify it matches our domain
- **Default fallback**: Always have a safe default redirect
- **Logging**: Track redirect attempts for security monitoring

For SPAs with dynamic routes, you need a more sophisticated approach that validates the URL structure rather than exact paths. Here's a production-ready pattern used by enterprise applications:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.regex.Pattern;
import java.util.logging.Logger;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;

@WebServlet("/auth/login")
public class ProductionLoginServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(ProductionLoginServlet.class.getName());
    private static final String DEFAULT_REDIRECT = "/app/dashboard";
    private static final String HMAC_SECRET = System.getenv("REDIRECT_HMAC_SECRET");

    // Pattern for allowed path characters (alphanumeric, slashes, hyphens, underscores)
    private static final Pattern SAFE_PATH_PATTERN = Pattern.compile("^/[a-zA-Z0-9/_-]+$");

    // Maximum redirect URL length to prevent DoS
    private static final int MAX_REDIRECT_LENGTH = 2048;

    // Blocked path patterns (admin areas, API endpoints, etc.)
    private static final Pattern BLOCKED_PATHS = Pattern.compile(
        "^/(api|admin|internal|logout|auth)/.*$", Pattern.CASE_INSENSITIVE
    );

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String redirectUrl = request.getParameter("redirect");
        String redirectToken = request.getParameter("redirect_token");

        // Rate limiting check (implement with Redis/cache)
        if (isRateLimited(request.getRemoteAddr())) {
            response.setStatus(429);
            response.getWriter().write("{\"error\": \"Too many requests\"}");
            return;
        }

        if (authenticateUser(username, password)) {
            HttpSession session = request.getSession(true);
            session.setAttribute("user", username);
            session.setAttribute("authenticated", true);

            // Regenerate session ID to prevent fixation
            String oldSessionId = session.getId();
            request.changeSessionId();

            // Validate redirect with multiple layers
            String safeRedirect = validateRedirectUrlProduction(
                redirectUrl, 
                redirectToken,
                request
            );

            // Audit log
            logSecurityEvent("LOGIN_SUCCESS", username, request, safeRedirect);

            // Set security headers
            response.setHeader("X-Content-Type-Options", "nosniff");
            response.setHeader("X-Frame-Options", "DENY");
            response.setHeader("Cache-Control", "no-store, no-cache, must-revalidate");

            response.sendRedirect(safeRedirect);
        } else {
            logSecurityEvent("LOGIN_FAILURE", username, request, null);
            incrementFailedAttempts(request.getRemoteAddr(), username);
            response.sendRedirect("/auth/login?error=invalid");
        }
    }

    private String validateRedirectUrlProduction(String redirectUrl, String token, 
            HttpServletRequest request) {

        // Layer 1: Null/empty check
        if (redirectUrl == null || redirectUrl.trim().isEmpty()) {
            return DEFAULT_REDIRECT;
        }

        // Layer 2: Length check (prevent DoS)
        if (redirectUrl.length() > MAX_REDIRECT_LENGTH) {
            logger.warning("Redirect URL exceeds maximum length");
            return DEFAULT_REDIRECT;
        }

        try {
            // Layer 3: URL decode and normalize
            String decoded = java.net.URLDecoder.decode(redirectUrl, "UTF-8");

            // Layer 4: Block dangerous schemes
            String lowercase = decoded.toLowerCase().trim();
            if (containsDangerousScheme(lowercase)) {
                logSecurityEvent("REDIRECT_BLOCKED_SCHEME", null, request, redirectUrl);
                return DEFAULT_REDIRECT;
            }

            // Layer 5: Parse and validate URI structure
            URI uri = new URI(decoded).normalize();

            // Layer 6: Reject absolute URLs with different host
            if (uri.isAbsolute()) {
                if (!isAllowedHost(uri.getHost(), request)) {
                    logSecurityEvent("REDIRECT_BLOCKED_HOST", null, request, redirectUrl);
                    return DEFAULT_REDIRECT;
                }
            }

            // Layer 7: Validate path structure
            String path = uri.getPath();
            if (path == null || !SAFE_PATH_PATTERN.matcher(path).matches()) {
                logSecurityEvent("REDIRECT_BLOCKED_PATH", null, request, redirectUrl);
                return DEFAULT_REDIRECT;
            }

            // Layer 8: Block sensitive paths
            if (BLOCKED_PATHS.matcher(path).matches()) {
                logSecurityEvent("REDIRECT_BLOCKED_SENSITIVE", null, request, redirectUrl);
                return DEFAULT_REDIRECT;
            }

            // Layer 9: Verify HMAC token if provided (for pre-generated redirects)
            if (token != null && !verifyRedirectToken(path, token)) {
                logSecurityEvent("REDIRECT_INVALID_TOKEN", null, request, redirectUrl);
                return DEFAULT_REDIRECT;
            }

            // Layer 10: Double-encoding check
            if (containsEncodedCharacters(path)) {
                logSecurityEvent("REDIRECT_DOUBLE_ENCODING", null, request, redirectUrl);
                return DEFAULT_REDIRECT;
            }

            return path;

        } catch (URISyntaxException | java.io.UnsupportedEncodingException e) {
            logger.warning("Failed to parse redirect URL: " + e.getMessage());
            return DEFAULT_REDIRECT;
        }
    }

    private boolean containsDangerousScheme(String url) {
        return url.startsWith("javascript:") ||
               url.startsWith("data:") ||
               url.startsWith("vbscript:") ||
               url.startsWith("file:") ||
               url.contains("\\n") ||
               url.contains("\\r") ||
               url.startsWith("//");  // Protocol-relative URLs
    }

    private boolean isAllowedHost(String host, HttpServletRequest request) {
        if (host == null) return true;  // Relative URL

        String expectedHost = request.getServerName();

        // Exact match
        if (host.equalsIgnoreCase(expectedHost)) return true;

        // Check against allowed subdomains (if configured)
        String[] allowedDomains = {"app.example.com", "dashboard.example.com"};
        for (String allowed : allowedDomains) {
            if (host.equalsIgnoreCase(allowed)) return true;
        }

        return false;
    }

    private boolean containsEncodedCharacters(String path) {
        return path.contains("%2f") || path.contains("%2F") ||
               path.contains("%5c") || path.contains("%5C") ||
               path.contains("%2e") || path.contains("%2E");
    }

    // Generate signed redirect token (use when creating links)
    public static String generateRedirectToken(String path) {
        try {
            Mac hmac = Mac.getInstance("HmacSHA256");
            hmac.init(new SecretKeySpec(HMAC_SECRET.getBytes(), "HmacSHA256"));
            byte[] hash = hmac.doFinal(path.getBytes());
            return Base64.getUrlEncoder().withoutPadding().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Failed to generate token", e);
        }
    }

    private boolean verifyRedirectToken(String path, String token) {
        String expected = generateRedirectToken(path);
        return MessageDigest.isEqual(expected.getBytes(), token.getBytes());
    }

