**Why This Is Dangerous**:
- Any website can submit forms to your authentication endpoints using the victim's session cookie
- Attackers can change passwords, email addresses, or other account settings without user knowledge
- The browser automatically includes session cookies in cross-origin POST requests
- No verification that the request originated from your legitimate application

**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"html/template"
	"log"
	"net/http"

	"github.com/gorilla/csrf"
	"github.com/gorilla/mux"
	"github.com/gorilla/sessions"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

var db *sql.DB
var store = sessions.NewCookieStore([]byte("secure-session-key-32-bytes!!"))
var templates = template.Must(template.ParseGlob("templates/*.html"))

// SECURE: CSRF-protected password change handler
func changePasswordHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method == http.MethodGet {
		// Include CSRF token in form template
		data := map[string]interface{}{
			"CSRFToken": csrf.Token(r),
		}
		templates.ExecuteTemplate(w, "change_password.html", data)
		return
	}

	session, err := store.Get(r, "session")
	if err != nil || session.Values["user_id"] == nil {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}
	userID := session.Values["user_id"].(int)

	// Require current password verification for sensitive changes
	currentPassword := r.FormValue("current_password")
	newPassword := r.FormValue("new_password")
	confirmPassword := r.FormValue("confirm_password")

	// Verify current password before allowing change
	var storedHash string
	err = db.QueryRow("SELECT password FROM users WHERE id = $1", userID).Scan(&storedHash)
	if err != nil {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(currentPassword)); err != nil {
		http.Error(w, "Current password is incorrect", http.StatusForbidden)
		return
	}

	if newPassword != confirmPassword || len(newPassword) < 12 {
		http.Error(w, "Invalid password", http.StatusBadRequest)
		return
	}

	hashedPassword, _ := bcrypt.GenerateFromPassword([]byte(newPassword), bcrypt.DefaultCost)
	_, err = db.Exec("UPDATE users SET password = $1 WHERE id = $2", hashedPassword, userID)
	if err != nil {
		log.Printf("Password update failed for user %d: %v", userID, err)
		http.Error(w, "Failed to update password", http.StatusInternalServerError)
		return
	}

	log.Printf("Password changed for user %d from IP %s", userID, r.RemoteAddr)
	http.Redirect(w, r, "/profile?success=password_changed", http.StatusSeeOther)
}

func main() {
	// 32-byte key for CSRF protection (use env variable in production)
	csrfKey := []byte("32-byte-long-auth-key-here!!!!!")

	r := mux.NewRouter()
	r.HandleFunc("/change-password", changePasswordHandler).Methods("GET", "POST")

	// CSRF middleware protects all routes
	csrfMiddleware := csrf.Protect(
		csrfKey,
		csrf.Secure(true),              // Require HTTPS
		csrf.HttpOnly(true),             // Cookie not accessible via JS
		csrf.SameSite(csrf.SameSiteStrictMode),
	)

	log.Println("Server starting on :8080 with CSRF protection")
	http.ListenAndServe(":8080", csrfMiddleware(r))
}
```

**Key Security Controls**:
- **CSRF Token Validation**: gorilla/csrf middleware generates and validates tokens automatically for each session
- **SameSite Cookie Attribute**: Prevents cookies from being sent in cross-origin requests
- **Current Password Verification**: Requires users to confirm identity before sensitive changes
- **Secure Cookie Flags**: HttpOnly and Secure prevent token theft via XSS or network interception

For SPAs and JSON APIs, CSRF protection requires a different approach since traditional form-based tokens don't apply to AJAX requests. The key is to use custom headers that browsers won't include in cross-origin requests, combined with proper CORS configuration.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"database/sql"
	"encoding/base64"
	"encoding/json"
	"log"
	"net/http"
	"strings"
	"time"

	"github.com/gorilla/mux"
	"github.com/gorilla/sessions"
	"github.com/rs/cors"
	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
	_ "github.com/lib/pq"
)

var db *sql.DB
var store = sessions.NewCookieStore([]byte("secure-session-key-32-bytes!!"))

type PasswordChangeRequest struct {
	CurrentPassword string `json:"current_password"`
	NewPassword     string `json:"new_password"`
	ConfirmPassword string `json:"confirm_password"`
}

type APIResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
	Error   string `json:"error,omitempty"`
}

// Rate limiter: 5 requests per minute per IP
var rateLimiters = make(map[string]*rate.Limiter)

func getRateLimiter(ip string) *rate.Limiter {
	if limiter, exists := rateLimiters[ip]; exists {
		return limiter
	}
	limiter := rate.NewLimiter(rate.Every(12*time.Second), 5)
	rateLimiters[ip] = limiter
	return limiter
}

// Generate secure CSRF token
func generateCSRFToken() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// CSRF middleware for JSON APIs using double-submit pattern
func csrfProtection(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Skip CSRF for safe methods
		if r.Method == http.MethodGet || r.Method == http.MethodHead || r.Method == http.MethodOptions {
			next.ServeHTTP(w, r)
			return
		}

		// Verify Content-Type is JSON (browsers can't set this cross-origin)
		contentType := r.Header.Get("Content-Type")
		if !strings.HasPrefix(contentType, "application/json") {
			log.Printf("CSRF: Invalid Content-Type from %s: %s", r.RemoteAddr, contentType)
			http.Error(w, `{"error":"Invalid content type"}`, http.StatusBadRequest)
			return
		}

		// Verify custom header exists (browsers won't include this cross-origin)
		csrfHeader := r.Header.Get("X-CSRF-Token")
		if csrfHeader == "" {
			log.Printf("CSRF: Missing X-CSRF-Token from %s", r.RemoteAddr)
			http.Error(w, `{"error":"CSRF token required"}`, http.StatusForbidden)
			return
		}

		// Double-submit validation: compare header token with cookie token
		csrfCookie, err := r.Cookie("csrf_token")
		if err != nil || csrfCookie.Value != csrfHeader {
			log.Printf("CSRF: Token mismatch from %s", r.RemoteAddr)
			http.Error(w, `{"error":"Invalid CSRF token"}`, http.StatusForbidden)
			return
		}

		// Verify Origin header matches expected domain
		origin := r.Header.Get("Origin")
		if origin != "" && origin != "https://myapp.com" {
			log.Printf("CSRF: Invalid origin from %s: %s", r.RemoteAddr, origin)
			http.Error(w, `{"error":"Invalid origin"}`, http.StatusForbidden)
			return
		}

		next.ServeHTTP(w, r)
	})
}

// Authentication middleware
func authMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		session, err := store.Get(r, "session")
		if err != nil || session.Values["user_id"] == nil {
			http.Error(w, `{"error":"Unauthorized"}`, http.StatusUnauthorized)
			return
		}

		userID := session.Values["user_id"].(int)
		ctx := context.WithValue(r.Context(), "user_id", userID)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// Rate limiting middleware
func rateLimitMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ip := strings.Split(r.RemoteAddr, ":")[0]
		limiter := getRateLimiter(ip)

		if !limiter.Allow() {
			log.Printf("Rate limit exceeded for IP: %s on %s", ip, r.URL.Path)
			w.Header().Set("Retry-After", "60")
			http.Error(w, `{"error":"Too many requests"}`, http.StatusTooManyRequests)
			return
		}

		next.ServeHTTP(w, r)
	})
}

// Endpoint to get CSRF token for SPA
func getCSRFTokenHandler(w http.ResponseWriter, r *http.Request) {
	token, err := generateCSRFToken()
	if err != nil {
		http.Error(w, `{"error":"Failed to generate token"}`, http.StatusInternalServerError)
		return
	}

	// Set CSRF token in HttpOnly cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "csrf_token",
		Value:    token,
		HttpOnly: false, // Must be readable by JavaScript for header
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		Path:     "/",
		MaxAge:   3600,
	})

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"csrf_token": token})
}

// SECURE: Password change API endpoint
func apiChangePasswordHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	userID := r.Context().Value("user_id").(int)

	var req PasswordChangeRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		json.NewEncoder(w).Encode(APIResponse{Success: false, Error: "Invalid request body"})
		return
	}

	// Verify current password
	var storedHash string
	err := db.QueryRow("SELECT password FROM users WHERE id = $1", userID).Scan(&storedHash)
	if err != nil {
		log.Printf("User %d not found during password change", userID)
		json.NewEncoder(w).Encode(APIResponse{Success: false, Error: "User not found"})
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(req.CurrentPassword)); err != nil {
		log.Printf("Failed password verification for user %d from %s", userID, r.RemoteAddr)
		w.WriteHeader(http.StatusForbidden)
		json.NewEncoder(w).Encode(APIResponse{Success: false, Error: "Current password incorrect"})
		return
	}

	// Validate new password
	if req.NewPassword != req.ConfirmPassword {
		json.NewEncoder(w).Encode(APIResponse{Success: false, Error: "Passwords don't match"})
		return
	}

	if len(req.NewPassword) < 12 {
		json.NewEncoder(w).Encode(APIResponse{Success: false, Error: "Password must be at least 12 characters"})
		return
	}

	// Update password
	hashedPassword, _ := bcrypt.GenerateFromPassword([]byte(req.NewPassword), bcrypt.DefaultCost)
	_, err = db.Exec("UPDATE users SET password = $1, updated_at = $2 WHERE id = $3",
		hashedPassword, time.Now(), userID)
	if err != nil {
		log.Printf("Password update failed for user %d: %v", userID, err)
		w.WriteHeader(http.StatusInternalServerError)
		json.NewEncoder(w).Encode(APIResponse{Success: false, Error: "Failed to update password"})
		return
	}

	// Audit log
	log.Printf("SECURITY: Password changed for user %d from IP %s User-Agent: %s",
		userID, r.RemoteAddr, r.Header.Get("User-Agent"))

	// Invalidate other sessions (optional but recommended)
	// invalidateOtherSessions(userID, r)

	json.NewEncoder(w).Encode(APIResponse{Success: true, Message: "Password updated successfully"})
}

func main() {
	r := mux.NewRouter()

	// Public endpoint to get CSRF token
	r.HandleFunc("/api/csrf-token", getCSRFTokenHandler).Methods("GET")

	// Protected API routes
	api := r.PathPrefix("/api").Subrouter()
	api.Use(rateLimitMiddleware)
	api.Use(csrfProtection)
	api.Use(authMiddleware)

	api.HandleFunc("/change-password", apiChangePasswordHandler).Methods("POST")

	// Strict CORS configuration
	c := cors.New(cors.Options{
		AllowedOrigins:   []string{"https://myapp.com"},
		AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE"},
		AllowedHeaders:   []string{"Content-Type", "X-CSRF-Token", "Authorization"},
		AllowCredentials: true,
		MaxAge:           300,
	})

	handler := c.Handler(r)

	log.Println("API server starting on :8080 with CSRF and CORS protection")
	http.ListenAndServe(":8080", handler)
}
```

**Defense in Depth Layers**:

1. **Custom Header Requirement**: Browsers enforce that cross-origin requests cannot include custom headers without CORS preflight approval:
```go
csrfHeader := r.Header.Get("X-CSRF-Token")
if csrfHeader == "" {
    http.Error(w, `{"error":"CSRF token required"}`, http.StatusForbidden)
    return
}
```

2. **Double-Submit Cookie Pattern**: Token must match in both cookie and header:
```go
csrfCookie, err := r.Cookie("csrf_token")
if err != nil || csrfCookie.Value != csrfHeader {
    http.Error(w, `{"error":"Invalid CSRF token"}`, http.StatusForbidden)
    return
}
```

3. **Strict CORS Configuration**: Only allow requests from your domain:
```go
c := cors.New(cors.Options{
    AllowedOrigins:   []string{"https://myapp.com"},
    AllowedHeaders:   []string{"Content-Type", "X-CSRF-Token"},
    AllowCredentials: true,
})
```

**Additional Protections**:

- **Rate Limiting**: Prevents brute-force attacks on authentication endpoints (5 requests per minute per IP)
- **Content-Type Validation**: Rejects non-JSON requests to state-changing endpoints
- **Origin Header Verification**: Secondary check that request comes from expected domain
- **SameSite=Strict Cookies**: Prevents cookies from being sent in cross-site requests even for top-level navigation
- **Audit Logging**: Records all security-sensitive operations with IP, user agent, and timestamp
- **Re-authentication**: Requires current password for credential changes even with valid session
- **Session Invalidation**: Consider invalidating other sessions after password change to force re-login

