            if ($user && password_verify($password, $user['password_hash'])) {
                session_regenerate_id(true);
                $_SESSION['user_id'] = $user['id'];
                $_SESSION['logged_in'] = true;

                // SECURE: Validate redirect URL
                $redirect_url = $this->validateRedirectUrl($_POST['redirect'] ?? '');

                header("Location: " . $redirect_url);
                exit();
            }
        }

        // Generate CSRF token
        $_SESSION['csrf_token'] = bin2hex(random_bytes(32));

        // Validate redirect before displaying
        $redirect = $this->validateRedirectUrl($_GET['redirect'] ?? '');

        echo '<form method="POST">';
        echo '<input type="hidden" name="csrf_token" value="' . $_SESSION['csrf_token'] . '">';
        echo '<input type="hidden" name="redirect" value="' . htmlspecialchars($redirect) . '">';
        echo '<input name="username" placeholder="Username">';
        echo '<input type="password" name="password" placeholder="Password">';
        echo '<button type="submit">Login</button>';
        echo '</form>';
    }

    private function validateCsrfToken($token) {
        return isset($_SESSION['csrf_token']) && 
               hash_equals($_SESSION['csrf_token'], $token);
    }
}
