<?php
// secure_redirect.php - Production-grade redirect validation with dynamic paths

namespace App\Security;

class SecureRedirectValidator {

    // Route patterns with regex - order matters (most specific first)
    private array $allowed_patterns = [
        '#^/dashboard$#',
        '#^/profile$#',
        '#^/settings(/[a-z]+)?$#',
        '#^/products/[0-9]+$#',                    // /products/123
        '#^/orders/[a-zA-Z0-9\-]+$#',             // /orders/abc-xyz-123
        '#^/categories/[a-z\-]+/items$#',         // /categories/electronics/items
        '#^/users/[0-9]+/profile$#',              // /users/456/profile
        '#^/search\?q=[a-zA-Z0-9\s%+]+$#',       // /search?q=term (limited chars)
    ];

    private string $defaultRedirect = '/dashboard';
    private $logger;

    public function __construct($logger = null) {
        $this->logger = $logger;
    }

    /**
     * Comprehensive redirect URL validation
     */
    public function validate(string $url): string {
        // Step 1: Empty or whitespace check
        $url = trim($url);
        if (empty($url)) {
            return $this->defaultRedirect;
        }

        // Step 2: Length limit to prevent ReDoS and buffer issues
        if (strlen($url) > 2048) {
            $this->logAttempt('URL too long', $url);
            return $this->defaultRedirect;
        }

        // Step 3: Decode URL to catch double-encoding attacks
        $decoded = $this->safeUrlDecode($url);
        if ($decoded === false) {
            $this->logAttempt('Malformed URL encoding', $url);
            return $this->defaultRedirect;
        }

        // Step 4: Block dangerous patterns BEFORE any parsing
        if ($this->containsDangerousPatterns($decoded)) {
            $this->logAttempt('Dangerous pattern detected', $url);
            return $this->defaultRedirect;
        }

        // Step 5: Parse and validate URL structure
        $parsed = $this->parseAndValidate($decoded);
        if ($parsed === false) {
            $this->logAttempt('Invalid URL structure', $url);
            return $this->defaultRedirect;
        }

        // Step 6: Match against allowed patterns
        $path = $parsed['path'];
        if (isset($parsed['query'])) {
            $path .= '?' . $parsed['query'];
        }

        if (!$this->matchesAllowedPattern($path)) {
            $this->logAttempt('Path not in allowlist', $url);
            return $this->defaultRedirect;
        }

        return $path;
    }

    /**
     * Safe URL decoding with loop detection
     */
    private function safeUrlDecode(string $url): string|false {
        $maxIterations = 3;
        $current = $url;

        for ($i = 0; $i < $maxIterations; $i++) {
            $decoded = urldecode($current);
            if ($decoded === $current) {
                return $decoded;
            }
            $current = $decoded;
        }

        // Still decoding after max iterations = attack attempt
        return false;
    }

    /**
     * Block dangerous URL patterns
     */
    private function containsDangerousPatterns(string $url): bool {
        $patterns = [
            // Protocol handlers
            '/^[a-z][a-z0-9+.\-]*:/i',
            // Protocol-relative URLs
            '/^\/\//i',
            // Backslash variants (IE compatibility issues)
            '/^\\\\/',
            '/^\/\\\\/',
            // NULL bytes and control characters
            '/[\x00-\x1f\x7f]/',
            // HTML entities that could decode to dangerous values
            '/&#/i',
            '/&[a-z]+;/i',
            // Directory traversal
            '/\.\.\//',
            '/\.\.\\\\/',
            // URL with credentials
            '/:.*@/',
            // Newlines (header injection)
            '/[\r\n]/',
        ];

        foreach ($patterns as $pattern) {
            if (preg_match($pattern, $url)) {
                return true;
            }
        }

        return false;
    }

    /**
     * Parse URL and validate it's same-origin relative
     */
    private function parseAndValidate(string $url): array|false {
        // Must start with single forward slash
        if (!preg_match('/^\/[^\/\\\\]/', $url) && $url !== '/') {
            return false;
        }

        $parsed = parse_url($url);
        if ($parsed === false) {
            return false;
        }

        // Must NOT have scheme, host, port, or user components
        if (isset($parsed['scheme']) || 
            isset($parsed['host']) || 
            isset($parsed['port']) ||
            isset($parsed['user']) ||
            isset($parsed['pass'])) {
            return false;
        }

        // Must have a path
        if (!isset($parsed['path'])) {
            return false;
        }

        // Normalize the path
        $parsed['path'] = '/' . ltrim($parsed['path'], '/');

        return $parsed;
    }

    /**
     * Match path against allowed patterns
     */
    private function matchesAllowedPattern(string $path): bool {
        foreach ($this->allowed_patterns as $pattern) {
            if (preg_match($pattern, $path)) {
                return true;
            }
        }
        return false;
    }

    /**
     * Log suspicious redirect attempts
     */
    private function logAttempt(string $reason, string $url): void {
        $logEntry = [
            'timestamp' => date('c'),
            'event' => 'blocked_redirect',
            'reason' => $reason,
            'url' => substr($url, 0, 500),
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => substr($_SERVER['HTTP_USER_AGENT'] ?? '', 0, 200),
            'referer' => substr($_SERVER['HTTP_REFERER'] ?? '', 0, 200),
        ];

        if ($this->logger) {
            $this->logger->warning('Blocked redirect attempt', $logEntry);
        } else {
            error_log(json_encode($logEntry));
        }
    }
}

/**
