class ProductionAuthController {
    private \PDO $pdo;
    private SecureRedirectValidator $redirectValidator;
    private $logger;
    private RateLimiter $rateLimiter;

    public function __construct(\PDO $pdo, $logger, RateLimiter $rateLimiter) {
        $this->pdo = $pdo;
        $this->logger = $logger;
        $this->rateLimiter = $rateLimiter;
        $this->redirectValidator = new SecureRedirectValidator($logger);
    }

    public function login(): void {
        // Security headers
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('Referrer-Policy: strict-origin-when-cross-origin');

        $clientIp = $this->getClientIp();

        // Rate limiting check
        if (!$this->rateLimiter->check($clientIp, 'login', 5, 300)) {
            $this->logger->warning('Rate limit exceeded for login', ['ip' => $clientIp]);
            http_response_code(429);
            header('Retry-After: 300');
            die('Too many login attempts. Please try again later.');
        }

        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            $this->handleLoginPost($clientIp);
        } else {
            $this->displayLoginForm();
        }
    }

    private function handleLoginPost(string $clientIp): void {
        // CSRF validation
        if (!$this->validateCsrf()) {
            $this->logger->warning('CSRF validation failed', ['ip' => $clientIp]);
            http_response_code(403);
            die('Invalid request');
        }

        $username = trim($_POST['username'] ?? '');
        $password = $_POST['password'] ?? '';

        // Input validation
        if (strlen($username) < 3 || strlen($username) > 64) {
            $this->displayLoginForm('Invalid credentials');
            return;
        }

        // Constant-time user lookup to prevent timing attacks
        $stmt = $this->pdo->prepare(
            "SELECT id, username, password_hash, failed_attempts, locked_until 
             FROM users WHERE username = ? LIMIT 1"
        );
        $stmt->execute([$username]);
        $user = $stmt->fetch(\PDO::FETCH_ASSOC);

        // Account lockout check
        if ($user && $user['locked_until'] && strtotime($user['locked_until']) > time()) {
            $this->logger->info('Login attempt on locked account', [
                'username' => $username,
                'ip' => $clientIp
            ]);
            $this->displayLoginForm('Account temporarily locked');
            return;
        }

        // Verify password (constant-time comparison via password_verify)
        $valid = $user && password_verify($password, $user['password_hash']);

        if (!$valid) {
            $this->handleFailedLogin($user, $username, $clientIp);
            return;
        }

        // Success - reset failed attempts
        $this->resetFailedAttempts($user['id']);

        // Regenerate session to prevent fixation
        session_regenerate_id(true);

        $_SESSION['user_id'] = $user['id'];
        $_SESSION['username'] = $user['username'];
        $_SESSION['logged_in'] = true;
        $_SESSION['login_time'] = time();
        $_SESSION['ip'] = $clientIp;

        // Audit log
        $this->logger->info('Successful login', [
            'user_id' => $user['id'],
            'username' => $user['username'],
            'ip' => $clientIp
        ]);

        // SECURE REDIRECT with full validation
        $redirectUrl = $this->redirectValidator->validate($_POST['redirect'] ?? '');

        header('Location: ' . $redirectUrl);
        exit();
    }

    private function handleFailedLogin(?array $user, string $username, string $clientIp): void {
        if ($user) {
            $attempts = ($user['failed_attempts'] ?? 0) + 1;
            $lockUntil = null;

            if ($attempts >= 5) {
                $lockUntil = date('Y-m-d H:i:s', time() + 900); // 15 minutes
            }

            $stmt = $this->pdo->prepare(
                "UPDATE users SET failed_attempts = ?, locked_until = ? WHERE id = ?"
            );
            $stmt->execute([$attempts, $lockUntil, $user['id']]);
        }

        $this->logger->warning('Failed login attempt', [
            'username' => $username,
            'ip' => $clientIp,
            'user_exists' => $user !== null
        ]);

        // Generic message to prevent username enumeration
        $this->displayLoginForm('Invalid credentials');
    }

    private function resetFailedAttempts(int $userId): void {
        $stmt = $this->pdo->prepare(
            "UPDATE users SET failed_attempts = 0, locked_until = NULL WHERE id = ?"
        );
        $stmt->execute([$userId]);
    }

    private function displayLoginForm(string $error = ''): void {
        $_SESSION['csrf_token'] = bin2hex(random_bytes(32));

        // Validate redirect BEFORE displaying in form
        $redirect = $this->redirectValidator->validate($_GET['redirect'] ?? '');

        // Template rendering would go here
        echo '<!DOCTYPE html><html><head><title>Login</title></head><body>';
        if ($error) {
            echo '<div class="error">' . htmlspecialchars($error) . '</div>';
        }
        echo '<form method="POST">';
        echo '<input type="hidden" name="csrf_token" value="' . $_SESSION['csrf_token'] . '">';
        echo '<input type="hidden" name="redirect" value="' . htmlspecialchars($redirect) . '">';
        echo '<input name="username" placeholder="Username" required>';
        echo '<input type="password" name="password" placeholder="Password" required>';
        echo '<button type="submit">Login</button>';
        echo '</form></body></html>';
    }

    private function validateCsrf(): bool {
        $token = $_POST['csrf_token'] ?? '';
        return isset($_SESSION['csrf_token']) && 
               hash_equals($_SESSION['csrf_token'], $token);
    }

    private function getClientIp(): string {
        // Only trust X-Forwarded-For if behind known proxy
        if (defined('TRUSTED_PROXIES') && in_array($_SERVER['REMOTE_ADDR'], TRUSTED_PROXIES)) {
            $forwarded = $_SERVER['HTTP_X_FORWARDED_FOR'] ?? '';
            $ips = array_map('trim', explode(',', $forwarded));
            return $ips[0] ?? $_SERVER['REMOTE_ADDR'];
        }
        return $_SERVER['REMOTE_ADDR'];
    }
}
