    db = g.pop('db', None)
    if db is not None:
        db.close()

def rate_limit(max_requests: int, window_seconds: int):
    """Rate limiting decorator for sensitive endpoints"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            current_time = time.time()
            key = f"{client_ip}:{f.__name__}"

            # Clean old entries and count recent requests
            if key in request_counts:
                request_counts[key] = [
                    t for t in request_counts[key]
                    if current_time - t < window_seconds
                ]
            else:
                request_counts[key] = []

            if len(request_counts[key]) >= max_requests:
                logger.warning(f"Rate limit exceeded for {client_ip} on {f.__name__}")
                return jsonify({'error': 'Too many requests'}), 429

            request_counts[key].append(current_time)
            return f(*args, **kwargs)
        return wrapped
    return decorator

def require_csrf_for_api(f):
    """Custom CSRF protection for JSON API endpoints"""
    @wraps(f)
    def wrapped(*args, **kwargs):
        # Check CSRF token from header (SPA pattern)
        csrf_token = request.headers.get('X-CSRF-Token')

        if not csrf_token:
            logger.warning(f"Missing CSRF token from {request.remote_addr}")
            return jsonify({'error': 'CSRF token required'}), 403

        # Validate token matches session
        try:
            csrf.protect()
        except Exception as e:
            logger.warning(f"Invalid CSRF token from {request.remote_addr}: {e}")
            return jsonify({'error': 'Invalid CSRF token'}), 403

        # Additional check: Verify Origin/Referer header
        origin = request.headers.get('Origin') or request.headers.get('Referer', '')
        allowed_origins = ['https://myapp.com', 'https://www.myapp.com']

        if not any(origin.startswith(allowed) for allowed in allowed_origins):
            logger.warning(f"Invalid origin {origin} from {request.remote_addr}")
            return jsonify({'error': 'Invalid origin'}), 403

        return f(*args, **kwargs)
    return wrapped

def require_auth(f):
    """Authentication decorator with session validation"""
    @wraps(f)
    def wrapped(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401

        # Validate session integrity
        if 'session_token' not in session:
            return jsonify({'error': 'Invalid session'}), 401

        return f(*args, **kwargs)
    return wrapped

