**Why This Is Dangerous**:
- Attackers send victims links to your legitimate login page with malicious returnUrl
- After successful authentication, users are redirected to attacker-controlled sites
- Phishing sites can mimic your dashboard and steal additional credentials or MFA codes
- Session tokens may leak via Referer header to malicious domain
- Users trust your domain, making phishing far more effective

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');
const url = require('url');

const app = express();
app.use(express.urlencoded({ extended: true }));
app.use(session({ 
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true, httpOnly: true, sameSite: 'strict' }
}));

// Allowed redirect destinations (whitelist approach)
const ALLOWED_REDIRECT_PATHS = ['/dashboard', '/profile', '/settings', '/orders'];
const ALLOWED_HOSTS = ['yoursite.com', 'www.yoursite.com'];

function isValidRedirectUrl(redirectUrl, req) {
  if (!redirectUrl || typeof redirectUrl !== 'string') {
    return false;
  }

  // Block javascript: and data: URLs
  if (/^(javascript|data|vbscript):/i.test(redirectUrl.trim())) {
    return false;
  }

  // Allow relative paths starting with / (but not //)
  if (redirectUrl.startsWith('/') && !redirectUrl.startsWith('//')) {
    // Validate against allowed paths
    const pathname = redirectUrl.split('?')[0].split('#')[0];
    return ALLOWED_REDIRECT_PATHS.some(allowed => 
      pathname === allowed || pathname.startsWith(allowed + '/')
    );
  }

  // For absolute URLs, validate the host
  try {
    const parsed = new URL(redirectUrl);
    return ALLOWED_HOSTS.includes(parsed.hostname) && parsed.protocol === 'https:';
  } catch (e) {
    return false;
  }
}

function sanitizeRedirectUrl(redirectUrl, req) {
  if (isValidRedirectUrl(redirectUrl, req)) {
    return redirectUrl;
  }
  return '/dashboard'; // Safe default
}

app.post('/login', async (req, res) => {
  const { username, password, returnUrl } = req.body;

  const user = await findUserByUsername(username);
  if (user && await bcrypt.compare(password, user.passwordHash)) {
    // Regenerate session to prevent fixation
    req.session.regenerate((err) => {
      if (err) {
        console.error('Session regeneration failed:', err);
        return res.status(500).send('Login failed');
      }

      req.session.userId = user.id;
      req.session.username = user.username;

      // SECURE: Validate and sanitize redirect URL
      const safeRedirect = sanitizeRedirectUrl(returnUrl, req);
      console.log(`User ${username} logged in, redirecting to: ${safeRedirect}`);
      return res.redirect(safeRedirect);
    });
  } else {
    res.status(401).send('Invalid credentials');
  }
});
```

**Key Security Controls**:
- **Whitelist validation**: Only allow redirects to known-safe paths or trusted hosts
- **Protocol enforcement**: Only allow https: URLs for absolute redirects
- **Block dangerous schemes**: Reject javascript:, data:, and vbscript: URLs
- **Path-only preference**: Prefer relative paths over absolute URLs when possible
- **Safe default**: Fall back to /dashboard if validation fails

Excellent questions. URL encoding bypass and deep link handling are common attack vectors that require additional defense layers. Attackers use techniques like double encoding, unicode normalization, and URL parser differentials to evade validation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const app = express();

// Security headers
app.use(helmet());
app.use(express.urlencoded({ extended: true }));

// Rate limiting for login
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: 'Too many login attempts, please try again later',
  standardHeaders: true,
  legacyHeaders: false
});

// Session configuration
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  name: '__Host-sessionId', // Cookie prefix for security
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 30 * 60 * 1000 // 30 minutes
  }
}));

// Configuration
const config = {
  allowedRedirectPatterns: [
    /^\/dashboard(\/.*)?$/,
    /^\/profile(\/.*)?$/,
    /^\/settings(\/.*)?$/,
    /^\/orders\/[a-zA-Z0-9-]+$/,
    /^\/products\/[0-9]+$/
  ],
  trustedDomains: new Set([
    'yoursite.com',
    'www.yoursite.com',
    'app.yoursite.com'
  ]),
  maxRedirectLength: 2048
};

class RedirectValidator {
  constructor(config) {
    this.config = config;
  }

  // Normalize URL to prevent encoding bypasses
  normalizeUrl(input) {
    if (!input || typeof input !== 'string') {
      return null;
    }

    // Enforce max length to prevent ReDoS
    if (input.length > this.config.maxRedirectLength) {
      return null;
    }

    try {
      // Decode multiple times to catch double/triple encoding
      let decoded = input;
      let previousDecoded = '';
      let iterations = 0;
      const maxIterations = 5;

      while (decoded !== previousDecoded && iterations < maxIterations) {
        previousDecoded = decoded;
        decoded = decodeURIComponent(decoded);
        iterations++;
      }

      // Normalize unicode
      decoded = decoded.normalize('NFKC');

      // Remove null bytes and control characters
      decoded = decoded.replace(/[\x00-\x1f\x7f]/g, '');

      return decoded.trim();
    } catch (e) {
      // Invalid encoding
      return null;
    }
  }

  // Check for dangerous URL patterns
  containsDangerousPatterns(url) {
    const dangerousPatterns = [
      /^\s*(javascript|data|vbscript|file):/i,
      /^\s*\/\//,  // Protocol-relative URLs
      /\/\.\.\//,  // Path traversal
      /@/,          // URL with credentials
      /%00/,        // Null byte
      /\\\//,       // Backslash confusion
      /^[^/]*:/     // Any protocol in non-absolute path position
    ];

    return dangerousPatterns.some(pattern => pattern.test(url));
  }

  // Validate relative path
  isValidRelativePath(path) {
    // Must start with single slash
    if (!path.startsWith('/') || path.startsWith('//')) {
      return false;
    }

    // Extract pathname without query string
    const pathname = path.split('?')[0].split('#')[0];

    // Check against allowed patterns
    return this.config.allowedRedirectPatterns.some(pattern => 
      pattern.test(pathname)
    );
  }

  // Validate absolute URL
  isValidAbsoluteUrl(urlString) {
    try {
      const parsed = new URL(urlString);

      // Must be HTTPS
      if (parsed.protocol !== 'https:') {
        return false;
      }

      // Check against trusted domains
      if (!this.config.trustedDomains.has(parsed.hostname)) {
        return false;
      }

      // No credentials in URL
      if (parsed.username || parsed.password) {
        return false;
      }

      // Validate the path portion
      return this.isValidRelativePath(parsed.pathname);
    } catch (e) {
      return false;
    }
  }

  // Main validation method
  validate(redirectUrl) {
    const normalized = this.normalizeUrl(redirectUrl);

    if (!normalized) {
      return { valid: false, reason: 'invalid_format' };
    }

    if (this.containsDangerousPatterns(normalized)) {
      return { valid: false, reason: 'dangerous_pattern' };
    }

    // Check if relative or absolute
    if (normalized.startsWith('/')) {
      if (this.isValidRelativePath(normalized)) {
        return { valid: true, url: normalized };
      }
      return { valid: false, reason: 'path_not_allowed' };
    }

    if (normalized.startsWith('http')) {
      if (this.isValidAbsoluteUrl(normalized)) {
        return { valid: true, url: normalized };
      }
      return { valid: false, reason: 'domain_not_trusted' };
    }

    return { valid: false, reason: 'unknown_format' };
  }
}

const redirectValidator = new RedirectValidator(config);

// Audit logging
function auditLog(event, details) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    event,
    ...details,
    requestId: crypto.randomUUID()
  };
  console.log(JSON.stringify(logEntry));
  // In production: send to SIEM/logging service
}

app.post('/login', loginLimiter, async (req, res) => {
  const { username, password, returnUrl } = req.body;
  const clientIp = req.ip;

  try {
    const user = await findUserByUsername(username);

    if (!user || !await bcrypt.compare(password, user.passwordHash)) {
      auditLog('LOGIN_FAILED', {
        username,
        clientIp,
        reason: 'invalid_credentials'
      });
      // Generic error to prevent user enumeration
      return res.status(401).send('Invalid credentials');
    }

    // Validate redirect URL before authentication completes
    const validation = redirectValidator.validate(returnUrl);

    if (!validation.valid) {
      auditLog('REDIRECT_BLOCKED', {
        username,
        clientIp,
        attemptedUrl: returnUrl,
        reason: validation.reason
      });
    }

    // Regenerate session
    req.session.regenerate((err) => {
      if (err) {
        auditLog('SESSION_ERROR', { username, clientIp, error: err.message });
        return res.status(500).send('Authentication failed');
      }

      req.session.userId = user.id;
      req.session.username = user.username;
      req.session.loginTime = Date.now();

      // Use validated URL or safe default
      const safeRedirect = validation.valid ? validation.url : '/dashboard';

      auditLog('LOGIN_SUCCESS', {
        userId: user.id,
        username,
        clientIp,
        redirectTo: safeRedirect,
        originalRedirect: returnUrl,
        redirectModified: !validation.valid
      });

      // Set CSP header to prevent inline script execution
      res.setHeader('Content-Security-Policy', "default-src 'self'");
      return res.redirect(303, safeRedirect); // Use 303 for POST redirect
    });
  } catch (error) {
    auditLog('LOGIN_ERROR', {
      username,
      clientIp,
      error: error.message
    });
    return res.status(500).send('Authentication failed');
  }
});

// Secure login page - use signed tokens instead of passing URL in form
app.get('/login', (req, res) => {
  const returnUrl = req.query.returnUrl;
  const validation = redirectValidator.validate(returnUrl);

  // Store validated return URL in session, not in form
  if (validation.valid) {
    req.session.pendingRedirect = validation.url;
  }

  // Render login form without exposing redirect URL
  res.send(`
    <!DOCTYPE html>
    <html>
    <head>
      <meta charset="UTF-8">
      <meta http-equiv="Content-Security-Policy" content="default-src 'self'">
    </head>
    <body>
      <form action="/login" method="POST">
        <input name="username" placeholder="Username" autocomplete="username">
        <input name="password" type="password" placeholder="Password" autocomplete="current-password">
        <button type="submit">Login</button>
      </form>
    </body>
    </html>
  `);
});

module.exports = { app, RedirectValidator };
```

**Defense in Depth Layers**:

1. **Multi-pass URL normalization**:
```javascript
// Decode multiple times to catch encoding bypass
let decoded = input;
let previousDecoded = '';
while (decoded !== previousDecoded && iterations < maxIterations) {
  previousDecoded = decoded;
  decoded = decodeURIComponent(decoded);
  iterations++;
}
```

2. **Pattern-based path validation with regex**:
```javascript
const allowedRedirectPatterns = [
  /^\/dashboard(\/.*)?$/,       // /dashboard and subpaths
  /^\/orders\/[a-zA-Z0-9-]+$/   // /orders/{order-id} with safe chars only
];
```

3. **Session-stored redirect instead of form field**:
```javascript
