**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"log"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

var db *sql.DB

// Allowed hosts for redirects (whitelist approach)
var allowedHosts = map[string]bool{
	"":                    true, // Allow relative paths
	"localhost:8080":      true,
	"www.myapp.com":       true,
	"myapp.com":           true,
	"dashboard.myapp.com": true,
}

func isValidRedirectURL(redirectURL string) bool {
	if redirectURL == "" {
		return false
	}

	// Parse the URL
	parsedURL, err := url.Parse(redirectURL)
	if err != nil {
		return false
	}

	// Block protocol-relative URLs (//evil.com)
	if strings.HasPrefix(redirectURL, "//") {
		return false
	}

	// Only allow relative paths or whitelisted hosts
	if parsedURL.Host == "" {
		// Relative URL - ensure it starts with / and doesn't contain backslashes
		if !strings.HasPrefix(redirectURL, "/") || strings.Contains(redirectURL, "\\") {
			return false
		}
		// Block encoded characters that could bypass checks
		if strings.Contains(redirectURL, "%") {
			return false
		}
		return true
	}

	// Only allow HTTPS for external redirects
	if parsedURL.Scheme != "" && parsedURL.Scheme != "https" {
		return false
	}

	// Check against whitelist
	return allowedHosts[parsedURL.Host]
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.ServeFile(w, r, "login.html")
		return
	}

	username := r.FormValue("username")
	password := r.FormValue("password")
	redirectURL := r.FormValue("redirect")

	// Authenticate user
	var hashedPassword string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", username).Scan(&hashedPassword)
	if err != nil {
		log.Printf("Login failed for user %s: user not found", username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(password)) != nil {
		log.Printf("Login failed for user %s: invalid password", username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Create secure session cookie
	http.SetCookie(w, &http.Cookie{
		Name:     "session",
		Value:    "secure_session_token",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
	})

	// SECURE: Validate redirect URL before use
	if isValidRedirectURL(redirectURL) {
		log.Printf("User %s logged in, redirecting to: %s", username, redirectURL)
		http.Redirect(w, r, redirectURL, http.StatusFound)
		return
	}

	// Default to safe fallback
	log.Printf("User %s logged in, using default redirect", username)
	http.Redirect(w, r, "/dashboard", http.StatusFound)
}

func main() {
	http.HandleFunc("/login", loginHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **Whitelist validation**: Only allows redirects to explicitly approved hosts, blocking all unknown destinations
- **Protocol enforcement**: Blocks protocol-relative URLs (`//evil.com`) and non-HTTPS schemes
- **Path validation**: Ensures relative paths start with `/` and don't contain bypass characters like backslashes or encoded sequences
- **Safe fallback**: Invalid or missing redirect URLs default to a known-safe page

Great question. Dynamic subdomain validation requires careful pattern matching to prevent subdomain takeover attacks and look-alike domain bypasses. Here's a production-ready implementation with multiple defense layers.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"database/sql"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
)

type RedirectValidator struct {
	db           *sql.DB
	redis        *redis.Client
	allowedBase  []string
	subdomainRe  *regexp.Regexp
	cache        sync.Map
	rateLimiters sync.Map
}

type AuditLog struct {
	Timestamp   time.Time `json:"timestamp"`
	UserID      string    `json:"user_id"`
	Action      string    `json:"action"`
	RedirectURL string    `json:"redirect_url"`
	Allowed     bool      `json:"allowed"`
	Reason      string    `json:"reason"`
	IPAddress   string    `json:"ip_address"`
	UserAgent   string    `json:"user_agent"`
}

func NewRedirectValidator(db *sql.DB, redisClient *redis.Client) *RedirectValidator {
	return &RedirectValidator{
		db:    db,
		redis: redisClient,
		allowedBase: []string{
			"myapp.com",
			"myapp.io",
		},
		// Only allow valid subdomain characters: alphanumeric and hyphens
		// Max length 63 chars per DNS label
		subdomainRe: regexp.MustCompile(`^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?\.`),
	}
}

func (v *RedirectValidator) ValidateRedirectURL(ctx context.Context, redirectURL, userID string) (bool, string) {
	if redirectURL == "" {
		return false, "empty_url"
	}

	// Normalize and parse URL
	normalized := strings.ToLower(strings.TrimSpace(redirectURL))

	// Block dangerous patterns before parsing
	dangerousPatterns := []string{
		"//",           // Protocol-relative
		"javascript:",  // JS injection
		"data:",        // Data URIs
		"vbscript:",    // VBScript
		"\\",           // Backslash bypass
		"%00",          // Null byte
		"%0a",          // Newline injection
		"%0d",          // Carriage return injection
	}

	for _, pattern := range dangerousPatterns {
		if strings.Contains(normalized, pattern) {
			return false, "dangerous_pattern:" + pattern
		}
	}

	// Handle relative URLs
	if strings.HasPrefix(normalized, "/") && !strings.HasPrefix(normalized, "//") {
		// Additional check for path traversal
		if strings.Contains(normalized, "..") {
			return false, "path_traversal"
		}
		return true, "relative_path"
	}

	// Parse absolute URL
	parsedURL, err := url.Parse(normalized)
	if err != nil {
		return false, "parse_error"
	}

	// Enforce HTTPS only
	if parsedURL.Scheme != "https" {
		return false, "non_https_scheme"
	}

	// Validate host
	host := parsedURL.Hostname()
	if host == "" {
		return false, "empty_host"
	}

	// Check for IP addresses (block them)
	if v.isIPAddress(host) {
		return false, "ip_address_blocked"
	}

	// Check if exact match to allowed base domains
	for _, baseDomain := range v.allowedBase {
		if host == baseDomain {
			return true, "base_domain_match"
		}
	}

	// Validate subdomain pattern
	for _, baseDomain := range v.allowedBase {
		if strings.HasSuffix(host, "."+baseDomain) {
			subdomain := strings.TrimSuffix(host, "."+baseDomain)

			// Validate subdomain format
			if !v.isValidSubdomainFormat(subdomain) {
				return false, "invalid_subdomain_format"
			}

			// Check if subdomain is registered to a valid tenant
			if v.isRegisteredSubdomain(ctx, subdomain, userID) {
				return true, "registered_subdomain"
			}

			return false, "unregistered_subdomain"
		}
	}

	return false, "domain_not_allowed"
}

func (v *RedirectValidator) isIPAddress(host string) bool {
	ipPattern := regexp.MustCompile(`^(\d{1,3}\.){3}\d{1,3}$|^\[.*\]$`)
	return ipPattern.MatchString(host)
}

func (v *RedirectValidator) isValidSubdomainFormat(subdomain string) bool {
	// Must be alphanumeric with hyphens, 1-63 chars
	if len(subdomain) == 0 || len(subdomain) > 63 {
		return false
	}

	// Cannot start or end with hyphen
	if strings.HasPrefix(subdomain, "-") || strings.HasSuffix(subdomain, "-") {
		return false
	}

	validPattern := regexp.MustCompile(`^[a-z0-9][a-z0-9-]*[a-z0-9]$|^[a-z0-9]$`)
	return validPattern.MatchString(subdomain)
}

func (v *RedirectValidator) isRegisteredSubdomain(ctx context.Context, subdomain, userID string) bool {
	// Check cache first
	cacheKey := fmt.Sprintf("subdomain:%s", subdomain)
	if cached, ok := v.cache.Load(cacheKey); ok {
		return cached.(bool)
	}

	// Check Redis for distributed cache
	result, err := v.redis.Get(ctx, cacheKey).Result()
	if err == nil {
		isValid := result == "valid"
		v.cache.Store(cacheKey, isValid)
		return isValid
	}

	// Query database
	var exists bool
	err = v.db.QueryRowContext(ctx,
		"SELECT EXISTS(SELECT 1 FROM tenants WHERE subdomain = $1 AND status = 'active')",
		subdomain,
	).Scan(&exists)

	if err != nil {
		log.Printf("Database error checking subdomain %s: %v", subdomain, err)
		return false // Fail closed
	}

	// Cache result
	if exists {
		v.redis.Set(ctx, cacheKey, "valid", 5*time.Minute)
	} else {
		v.redis.Set(ctx, cacheKey, "invalid", 1*time.Minute)
	}
	v.cache.Store(cacheKey, exists)

	return exists
}

func (v *RedirectValidator) LogRedirectAttempt(ctx context.Context, log AuditLog) {
	logData, _ := json.Marshal(log)
	v.redis.LPush(ctx, "audit:redirect_attempts", logData)

	// Alert on suspicious patterns
	if !log.Allowed {
		v.checkSuspiciousActivity(ctx, log)
	}
}

func (v *RedirectValidator) checkSuspiciousActivity(ctx context.Context, log AuditLog) {
	// Count failed attempts from this IP in last hour
	key := fmt.Sprintf("failed_redirects:%s", log.IPAddress)
	count, _ := v.redis.Incr(ctx, key).Result()
	v.redis.Expire(ctx, key, time.Hour)

	if count > 10 {
		// Trigger security alert
		fmt.Printf("SECURITY ALERT: Multiple failed redirect attempts from IP %s\n", log.IPAddress)
	}
}

func (v *RedirectValidator) getRateLimiter(ip string) *rate.Limiter {
	if limiter, ok := v.rateLimiters.Load(ip); ok {
		return limiter.(*rate.Limiter)
	}

	limiter := rate.NewLimiter(rate.Every(time.Second), 10) // 10 requests/second
	v.rateLimiters.Store(ip, limiter)
	return limiter
}

func generateCSRFToken() string {
	b := make([]byte, 32)
	rand.Read(b)
	return base64.URLEncoding.EncodeToString(b)
}

func (v *RedirectValidator) LoginHandler(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	clientIP := r.RemoteAddr

	// Rate limiting
	if !v.getRateLimiter(clientIP).Allow() {
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	if r.Method != http.MethodPost {
		// Generate CSRF token for login form
		token := generateCSRFToken()
		v.redis.Set(ctx, "csrf:"+token, "valid", 15*time.Minute)
		http.SetCookie(w, &http.Cookie{
			Name:     "csrf_token",
			Value:    token,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteStrictMode,
		})
		http.ServeFile(w, r, "login.html")
		return
	}

	// Verify CSRF token
	csrfCookie, err := r.Cookie("csrf_token")
	if err != nil || v.redis.Get(ctx, "csrf:"+csrfCookie.Value).Val() != "valid" {
		http.Error(w, "Invalid request", http.StatusForbidden)
		return
	}
	v.redis.Del(ctx, "csrf:"+csrfCookie.Value) // One-time use

	username := r.FormValue("username")
	password := r.FormValue("password")
	redirectURL := r.FormValue("redirect")

	// Authenticate (simplified)
	var userID, hashedPassword string
	err = v.db.QueryRowContext(ctx,
		"SELECT id, password_hash FROM users WHERE username = $1",
		username,
	).Scan(&userID, &hashedPassword)

	if err != nil || bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(password)) != nil {
		log.Printf("Login failed for user %s from IP %s", username, clientIP)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Validate redirect URL
	allowed, reason := v.ValidateRedirectURL(ctx, redirectURL, userID)

	// Audit log
	v.LogRedirectAttempt(ctx, AuditLog{
		Timestamp:   time.Now().UTC(),
		UserID:      userID,
		Action:      "post_login_redirect",
		RedirectURL: redirectURL,
		Allowed:     allowed,
		Reason:      reason,
		IPAddress:   clientIP,
		UserAgent:   r.UserAgent(),
	})

	// Set secure session cookie
	sessionToken := generateCSRFToken() // Use secure random for session
	http.SetCookie(w, &http.Cookie{
		Name:     "session",
		Value:    sessionToken,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   3600,
		Path:     "/",
	})

	// Redirect to validated URL or safe default
	finalRedirect := "/dashboard"
	if allowed {
		finalRedirect = redirectURL
	}

	http.Redirect(w, r, finalRedirect, http.StatusFound)
}
```

**Defense in Depth Layers**:

1. **Input Sanitization Layer**: Blocks dangerous patterns before URL parsing
```go
dangerousPatterns := []string{"//", "javascript:", "data:", "\\"}
for _, pattern := range dangerousPatterns {
    if strings.Contains(normalized, pattern) {
        return false, "dangerous_pattern"
    }
}
```

2. **Domain Validation Layer**: Strict subdomain pattern matching with DNS-compliant regex
```go
// Only alphanumeric and hyphens, 1-63 chars, no leading/trailing hyphens
validPattern := regexp.MustCompile(`^[a-z0-9][a-z0-9-]*[a-z0-9]$|^[a-z0-9]$`)
```

3. **Tenant Registration Layer**: Verifies subdomain belongs to active tenant in database
```go
"SELECT EXISTS(SELECT 1 FROM tenants WHERE subdomain = $1 AND status = 'active')"
```

4. **Behavioral Monitoring Layer**: Tracks failed redirect attempts and alerts on abuse
```go
if count > 10 {
    fmt.Printf("SECURITY ALERT: Multiple failed redirect attempts from IP %s\n", log.IPAddress)
}
```

**Additional Protections**:
- **CSRF protection**: One-time tokens prevent cross-site login attacks combined with redirect
- **Rate limiting**: Per-IP rate limits prevent enumeration of valid subdomains
- **Distributed caching**: Redis caching prevents database DoS during redirect validation
- **Fail closed**: Any validation error defaults to blocking the redirect
- **Comprehensive audit logging**: All redirect attempts logged for forensic analysis
- **IP address blocking**: Prevents redirects to IP addresses that could bypass DNS-based validation
- **Session cookie hardening**: HttpOnly, Secure, SameSite=Strict prevents session theft

Your login form may be vulnerable to Cross-Site Request Forgery (CSRF) attacks if it doesn't include proper CSRF protection. CSRF allows attackers to trick authenticated users into submitting malicious requests, potentially enabling account takeover through password changes or email updates.

**VULNERABLE CODE**:

```php
<?php
// login.php - VULNERABLE: No CSRF protection
session_start();

class AuthController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function login() {
        // No CSRF token validation!
        $username = $_POST['username'] ?? '';
        $password = $_POST['password'] ?? '';

        $stmt = $this->pdo->prepare("SELECT id, password_hash FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user && password_verify($password, $user['password_hash'])) {
            $_SESSION['user_id'] = $user['id'];
            $_SESSION['logged_in'] = true;
            header('Location: /dashboard');
            exit;
        }

        return "Invalid credentials";
    }

    public function changePassword() {
        // CRITICAL: No CSRF protection on password change!
        if (!isset($_SESSION['user_id'])) {
            header('Location: /login');
            exit;
        }

        $newPassword = $_POST['new_password'] ?? '';
        $hashedPassword = password_hash($newPassword, PASSWORD_DEFAULT);

        $stmt = $this->pdo->prepare("UPDATE users SET password_hash = ? WHERE id = ?");
        $stmt->execute([$hashedPassword, $_SESSION['user_id']]);

        return "Password changed successfully";
    }
}
?>
```

**Attack Payload** (malicious HTML hosted on attacker's site):
```html
<!-- attacker-site.com/steal-password.html -->
<html>
<body onload="document.getElementById('csrfForm').submit();">
  <h1>Loading...</h1>
  <form id="csrfForm" action="https://victim-site.com/change-password.php" method="POST">
    <input type="hidden" name="new_password" value="attacker123" />
  </form>
</body>
</html>
```

**Why This Is Dangerous**:
- Attacker can change victim's password without their knowledge by tricking them into visiting a malicious page
- Login forms without CSRF tokens can be targeted in login CSRF attacks (forcing victim to authenticate as attacker)
- Session fixation combined with CSRF allows complete account takeover
- Email change forms are particularly dangerous as they enable password reset attacks

**SECURE VERSION**:

```php
<?php
// secure_auth.php - CSRF Protected Authentication
session_start();

class CSRFProtection {
    public static function generateToken(): string {
        if (empty($_SESSION['csrf_token'])) {
            $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
            $_SESSION['csrf_token_time'] = time();
        }
        return $_SESSION['csrf_token'];
    }

    public static function validateToken(string $token): bool {
        if (empty($_SESSION['csrf_token']) || empty($token)) {
            return false;
        }

        // Token expiration (15 minutes)
        $tokenAge = time() - ($_SESSION['csrf_token_time'] ?? 0);
        if ($tokenAge > 900) {
            self::regenerateToken();
            return false;
        }

        return hash_equals($_SESSION['csrf_token'], $token);
    }

    public static function regenerateToken(): string {
        $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
        $_SESSION['csrf_token_time'] = time();
        return $_SESSION['csrf_token'];
    }
}

class SecureAuthController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function login(): string {
        // Validate CSRF token on ALL POST requests
        $csrfToken = $_POST['csrf_token'] ?? '';
        if (!CSRFProtection::validateToken($csrfToken)) {
            error_log("CSRF validation failed from IP: " . $_SERVER['REMOTE_ADDR']);
            http_response_code(403);
            return "Invalid request. Please refresh and try again.";
        }

        $username = trim($_POST['username'] ?? '');
        $password = $_POST['password'] ?? '';

        // Input validation
        if (empty($username) || empty($password)) {
            return "Username and password are required.";
        }

        $stmt = $this->pdo->prepare("SELECT id, password_hash FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user && password_verify($password, $user['password_hash'])) {
            // Regenerate session ID on login (prevent session fixation)
            session_regenerate_id(true);

            // Regenerate CSRF token after login
            CSRFProtection::regenerateToken();

            $_SESSION['user_id'] = $user['id'];
            $_SESSION['logged_in'] = true;
            $_SESSION['login_time'] = time();

            error_log("Successful login for user: " . $username);
            header('Location: /dashboard');
            exit;
        }

        error_log("Failed login attempt for user: " . $username . " from IP: " . $_SERVER['REMOTE_ADDR']);
        return "Invalid credentials";
    }

    public function changePassword(): string {
        // Verify user is authenticated
        if (!isset($_SESSION['user_id'])) {
            header('Location: /login');
            exit;
        }

        // CSRF validation for password change
        $csrfToken = $_POST['csrf_token'] ?? '';
        if (!CSRFProtection::validateToken($csrfToken)) {
            error_log("CSRF attack blocked on password change for user: " . $_SESSION['user_id']);
            http_response_code(403);
            return "Invalid request. Please refresh and try again.";
        }

        // Require current password for sensitive operations
        $currentPassword = $_POST['current_password'] ?? '';
        $newPassword = $_POST['new_password'] ?? '';

        // Verify current password
        $stmt = $this->pdo->prepare("SELECT password_hash FROM users WHERE id = ?");
        $stmt->execute([$_SESSION['user_id']]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$user || !password_verify($currentPassword, $user['password_hash'])) {
            return "Current password is incorrect.";
        }

        // Password strength validation
        if (strlen($newPassword) < 12) {
            return "Password must be at least 12 characters.";
        }

        $hashedPassword = password_hash($newPassword, PASSWORD_ARGON2ID);
        $stmt = $this->pdo->prepare("UPDATE users SET password_hash = ? WHERE id = ?");
        $stmt->execute([$hashedPassword, $_SESSION['user_id']]);

        // Regenerate CSRF token after sensitive action
        CSRFProtection::regenerateToken();

        error_log("Password changed for user: " . $_SESSION['user_id']);
        return "Password changed successfully";
    }
}
?>
```

**Key Security Controls**:
- **CSRF Token Validation**: Every state-changing request must include a valid CSRF token generated per-session
- **Token Timing Protection**: Using `hash_equals()` prevents timing attacks on token comparison
- **Session Regeneration**: Regenerating session ID on login prevents session fixation attacks
- **Re-authentication**: Requiring current password for sensitive operations provides additional protection

AJAX authentication endpoints require additional CSRF protection strategies since traditional hidden form fields don't work the same way. You need to use a combination of custom headers, double-submit cookies, and SameSite cookie attributes.

**PRODUCTION PATTERN**:

```php
<?php
// config/security.php - Security Configuration
define('CSRF_COOKIE_NAME', 'csrf_token');
define('CSRF_HEADER_NAME', 'X-CSRF-Token');
define('SESSION_TIMEOUT', 3600); // 1 hour
define('MAX_LOGIN_ATTEMPTS', 5);
define('LOCKOUT_DURATION', 900); // 15 minutes

// bootstrap.php - Secure Session Configuration
function initSecureSession(): void {
    ini_set('session.cookie_httponly', 1);
    ini_set('session.cookie_secure', 1);
    ini_set('session.cookie_samesite', 'Strict');
    ini_set('session.use_strict_mode', 1);
    ini_set('session.use_only_cookies', 1);

    session_start();

    // Session timeout check
    if (isset($_SESSION['last_activity']) && (time() - $_SESSION['last_activity'] > SESSION_TIMEOUT)) {
        session_unset();
        session_destroy();
        session_start();
    }
    $_SESSION['last_activity'] = time();
}

class AjaxCSRFProtection {
    private static $logger;

    public static function setLogger($logger): void {
        self::$logger = $logger;
    }

    public static function generateToken(): string {
        $token = bin2hex(random_bytes(32));
        $_SESSION['csrf_token'] = $token;
        $_SESSION['csrf_token_time'] = time();

        // Set double-submit cookie (SameSite=Strict prevents CSRF)
        setcookie(
            CSRF_COOKIE_NAME,
            $token,
            [
                'expires' => time() + 3600,
                'path' => '/',
                'domain' => $_SERVER['HTTP_HOST'],
                'secure' => true,
                'httponly' => false, // JavaScript needs to read this
                'samesite' => 'Strict'
            ]
        );

        return $token;
    }

    public static function validateAjaxRequest(): bool {
        // Check Origin header
        $origin = $_SERVER['HTTP_ORIGIN'] ?? '';
        $allowedOrigins = ['https://yourdomain.com', 'https://www.yourdomain.com'];

        if (!empty($origin) && !in_array($origin, $allowedOrigins, true)) {
            self::logSecurityEvent('Invalid Origin header', ['origin' => $origin]);
            return false;
        }

        // For AJAX, validate both header and cookie (double-submit)
        $headerToken = $_SERVER['HTTP_' . str_replace('-', '_', strtoupper(CSRF_HEADER_NAME))] ?? '';
        $cookieToken = $_COOKIE[CSRF_COOKIE_NAME] ?? '';
        $sessionToken = $_SESSION['csrf_token'] ?? '';

        if (empty($headerToken) || empty($cookieToken) || empty($sessionToken)) {
            self::logSecurityEvent('Missing CSRF tokens', [
                'has_header' => !empty($headerToken),
                'has_cookie' => !empty($cookieToken),
                'has_session' => !empty($sessionToken)
            ]);
            return false;
        }

        // All three must match (triple validation)
        if (!hash_equals($sessionToken, $headerToken) || !hash_equals($sessionToken, $cookieToken)) {
            self::logSecurityEvent('CSRF token mismatch');
            return false;
        }

        // Token age validation (15 minutes max)
        $tokenAge = time() - ($_SESSION['csrf_token_time'] ?? 0);
        if ($tokenAge > 900) {
            self::logSecurityEvent('CSRF token expired', ['age' => $tokenAge]);
            return false;
        }

        return true;
    }

    public static function setSecurityHeaders(): void {
        header('Content-Type: application/json; charset=utf-8');
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('X-XSS-Protection: 1; mode=block');
        header('Referrer-Policy: strict-origin-when-cross-origin');
        header('Cache-Control: no-store, no-cache, must-revalidate');
    }

    private static function logSecurityEvent(string $message, array $context = []): void {
        $logEntry = [
            'timestamp' => date('c'),
            'message' => $message,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            'user_id' => $_SESSION['user_id'] ?? null,
            'context' => $context
        ];

        error_log('[SECURITY] ' . json_encode($logEntry));
    }
}

class RateLimiter {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function isRateLimited(string $identifier): bool {
        $stmt = $this->pdo->prepare("
            SELECT COUNT(*) as attempts 
            FROM login_attempts 
            WHERE identifier = ? AND attempted_at > DATE_SUB(NOW(), INTERVAL ? SECOND)
        ");
        $stmt->execute([$identifier, LOCKOUT_DURATION]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);

        return ($result['attempts'] ?? 0) >= MAX_LOGIN_ATTEMPTS;
    }

    public function recordAttempt(string $identifier): void {
        $stmt = $this->pdo->prepare("INSERT INTO login_attempts (identifier, attempted_at) VALUES (?, NOW())");
        $stmt->execute([$identifier]);
    }

    public function clearAttempts(string $identifier): void {
        $stmt = $this->pdo->prepare("DELETE FROM login_attempts WHERE identifier = ?");
        $stmt->execute([$identifier]);
    }
}

class SecureAjaxAuthController {
    private $pdo;
    private $rateLimiter;

    public function __construct($pdo) {
        $this->pdo = $pdo;
        $this->rateLimiter = new RateLimiter($pdo);
    }

    public function handleAjaxLogin(): void {
        AjaxCSRFProtection::setSecurityHeaders();

        // Verify this is an AJAX request
        if (($_SERVER['HTTP_X_REQUESTED_WITH'] ?? '') !== 'XMLHttpRequest') {
            $this->sendJsonResponse(400, ['error' => 'Invalid request type']);
            return;
        }

        // Validate CSRF for login (protects against login CSRF)
        if (!AjaxCSRFProtection::validateAjaxRequest()) {
            $this->sendJsonResponse(403, ['error' => 'Invalid security token. Please refresh the page.']);
            return;
        }

        // Parse JSON body
        $input = json_decode(file_get_contents('php://input'), true);
        if (json_last_error() !== JSON_ERROR_NONE) {
            $this->sendJsonResponse(400, ['error' => 'Invalid request format']);
            return;
        }

        $username = trim($input['username'] ?? '');
        $password = $input['password'] ?? '';
        $clientIP = $_SERVER['REMOTE_ADDR'];

        // Rate limiting check
        $rateLimitKey = $clientIP . ':' . $username;
        if ($this->rateLimiter->isRateLimited($rateLimitKey)) {
            error_log("[SECURITY] Rate limit exceeded for: " . $rateLimitKey);
            $this->sendJsonResponse(429, [
                'error' => 'Too many login attempts. Please try again later.',
                'retry_after' => LOCKOUT_DURATION
            ]);
            return;
        }

        // Input validation
        if (empty($username) || empty($password)) {
            $this->sendJsonResponse(400, ['error' => 'Username and password are required']);
            return;
        }

        // Authenticate
        $stmt = $this->pdo->prepare("SELECT id, password_hash, is_active FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$user || !$user['is_active'] || !password_verify($password, $user['password_hash'])) {
            $this->rateLimiter->recordAttempt($rateLimitKey);
            error_log("[AUTH] Failed login for: " . $username . " from IP: " . $clientIP);

            // Generic error message (don't reveal if user exists)
            $this->sendJsonResponse(401, ['error' => 'Invalid credentials']);
            return;
        }

        // Successful authentication
        $this->rateLimiter->clearAttempts($rateLimitKey);
        session_regenerate_id(true);

        $_SESSION['user_id'] = $user['id'];
        $_SESSION['logged_in'] = true;
        $_SESSION['login_time'] = time();
        $_SESSION['ip_address'] = $clientIP;

        // Generate new CSRF token for authenticated session
        $newToken = AjaxCSRFProtection::generateToken();

        error_log("[AUTH] Successful login for user ID: " . $user['id']);

        $this->sendJsonResponse(200, [
            'success' => true,
            'redirect' => '/dashboard',
            'csrf_token' => $newToken
        ]);
    }

    private function sendJsonResponse(int $statusCode, array $data): void {
        http_response_code($statusCode);
        echo json_encode($data);
        exit;
    }
}

